// Create normalized `ROAD_NETWORK_GEOJSON_WGS84` from raw export.
// This will detect longitudes that appear to be shifted (~122 instead of 124)
// and apply a +2.0° correction so the dataset aligns with other layers.
let ROAD_NETWORK_GEOJSON_WGS84 = null;
(function normalizeRoads() {
	try {
		const raw = ROAD_NETWORK_GEOJSON_WGS84_RAW;
		const firstFeat = raw && raw.features && raw.features[0];
		let sampleLon = null;
		if (firstFeat && firstFeat.geometry && firstFeat.geometry.coordinates) {
			const c = firstFeat.geometry.coordinates;
			if (Array.isArray(c[0]) && Array.isArray(c[0][0])) sampleLon = c[0][0][0];
			else if (Array.isArray(c[0])) sampleLon = c[0][0];
			else sampleLon = c[0];
			if (Array.isArray(sampleLon)) sampleLon = sampleLon[0];
		}

		console.log('[ROAD NETWORK] Sample longitude detected:', sampleLon);
		const needsShift = typeof sampleLon === 'number' && sampleLon < 123;
		console.log('[ROAD NETWORK] Needs shift (< 123):', needsShift);
		
		if (!needsShift) {
			ROAD_NETWORK_GEOJSON_WGS84 = raw;
			console.log('[ROAD NETWORK] No shift applied - using raw coordinates');
			return;
		}

		const shift = 2.0;
		// Deep clone then adjust
		ROAD_NETWORK_GEOJSON_WGS84 = JSON.parse(JSON.stringify(raw));

		const adjust = (coords) => {
			if (!Array.isArray(coords)) return;
			if (coords.length >= 2 && typeof coords[0] === 'number' && typeof coords[1] === 'number') {
				coords[0] = coords[0] + shift;
				return;
			}
			for (let i = 0; i < coords.length; i++) adjust(coords[i]);
		};

		ROAD_NETWORK_GEOJSON_WGS84.features.forEach((f) => {
			if (f && f.geometry && f.geometry.coordinates) adjust(f.geometry.coordinates);
		});
		
		// Log first feature's first coordinate after shift
		const firstAfterShift = ROAD_NETWORK_GEOJSON_WGS84.features[0]?.geometry?.coordinates;
		let firstCoordAfter = null;
		if (firstAfterShift) {
			const c = firstAfterShift;
			if (Array.isArray(c[0]) && Array.isArray(c[0][0])) firstCoordAfter = [c[0][0][0], c[0][0][1]];
			else if (Array.isArray(c[0])) firstCoordAfter = [c[0][0], c[0][1]];
			else firstCoordAfter = [c[0], c[1]];
		}
		
		console.log('[ROAD NETWORK] Applied +' + shift + '° longitude shift');
		console.log('[ROAD NETWORK] First road feature first coord after shift: [' + (firstCoordAfter ? firstCoordAfter[0].toFixed(6) + ', ' + firstCoordAfter[1].toFixed(6) : 'N/A') + ']');
		console.log('[ROAD NETWORK] Total features shifted:', ROAD_NETWORK_GEOJSON_WGS84.features.length);
	} catch (e) {
		console.error('Error normalizing ROAD_NETWORK_GEOJSON_WGS84:', e);
		// Fall back to raw if anything goes wrong
		ROAD_NETWORK_GEOJSON_WGS84 = ROAD_NETWORK_GEOJSON_WGS84_RAW;
	}
})();

